'use client';

import { useMemo, useState } from 'react';
import type { LessonRecurrence, ScheduledLessonDto } from '@soenglish/shared-types';
import { useParams } from 'next/navigation';
import { EmptyStateCard } from '../../../components/ui';
import { ProfileViewShell } from '../../../components/profile/ProfileViewShell';
import { calculateEndTime } from '../../../features/calendar/adapters/lessonCalendarAdapter';
import {
  activeMockUser,
  canView,
  canManageStudent,
  getStudentById,
  getStudentScheduledLessons,
  type MockStudent,
  type UserRole,
} from '../../../mocks';
import { StudentCalendarTab, StudentProfileTab, StudentScheduleTab } from './sections';
import { BookOpen, Flame, MessageSquare, Target, Trophy } from 'lucide-react';

export default function StudentDetailsPage() {
  const params = useParams<{ studentId: string }>();
  const studentId = params?.studentId;
  const student = studentId ? getStudentById(studentId) : undefined;

  if (!canView('dashboard', activeMockUser.role)) return null;
  const allowedRoles = activeMockUser.role === 'teacher' || activeMockUser.role === 'admin' || activeMockUser.role === 'super-admin';
  if (!allowedRoles) {
    return <EmptyStateCard title="No permission" description="Students section is not available for your role." />;
  }
  if (!student) {
    return <EmptyStateCard title="Student not found" description="Check the student link and try again." />;
  }
  const canManage = canManageStudent(activeMockUser, student);
  if (!canManage) {
    return <EmptyStateCard title="No permission" description="You cannot manage this student." />;
  }

  const [tab, setTab] = useState<'profile' | 'calendar' | 'schedule'>('profile');
  const [studentForm, setStudentForm] = useState<MockStudent>(student);
  const [lessons, setLessons] = useState<ScheduledLessonDto[]>(getStudentScheduledLessons(student.id));
  const [lessonType, setLessonType] = useState('grammar');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [recurrence, setRecurrence] = useState<LessonRecurrence>('none');
  const [comment, setComment] = useState('');

  const pageSubtitle = useMemo(
    () => `Manage student profile, calendar and scheduling · ${activeMockUser.role as UserRole}`,
    [],
  );
  const achievementIcons = {
    flame: <Flame size={20} />,
    book: <BookOpen size={20} />,
    target: <Target size={20} />,
    trophy: <Trophy size={20} />,
    message: <MessageSquare size={20} />,
  } as const;
  const achievementMetaById: Record<string, { icon: keyof typeof achievementIcons; label: string; description: string }> = {
    'streak-3-days': { icon: 'flame', label: '3-Day Streak', description: 'Keep a 3-day learning streak.' },
    'streak-7-days': { icon: 'flame', label: '7-Day Streak', description: 'Keep a 7-day learning streak.' },
    'streak-14-days': { icon: 'flame', label: '14-Day Streak', description: 'Keep a 14-day learning streak.' },
    'words-100': { icon: 'book', label: '100 Words', description: 'Learn 100 words.' },
    'words-500': { icon: 'book', label: '500 Words', description: 'Learn 500 words.' },
    'quiz-first': { icon: 'target', label: 'First Quiz', description: 'Complete the first quiz.' },
    'quiz-perfect-1': { icon: 'trophy', label: 'Perfect Quiz', description: 'Get one perfect quiz score.' },
    'speaking-starter': { icon: 'message', label: 'Speaking Starter', description: 'Complete your first speaking session.' },
  };

  return (
    <ProfileViewShell
      title="Student Details"
      subtitle={pageSubtitle}
      avatar={studentForm.fullName
        .split(' ')
        .map((part) => part[0])
        .join('')
        .slice(0, 2)}
      name={studentForm.fullName}
      meta={`Teacher: ${studentForm.teacherName}`}
      badges={[
        { label: studentForm.level },
        { label: studentForm.status, variant: studentForm.status === 'active' ? 'green' : 'amber' },
        { label: studentForm.scheduleType === 'fixed' ? 'Fixed schedule' : 'Flexible schedule' },
      ]}
      stats={[
        { value: studentForm.wordsLearned, label: 'Words' },
        { value: studentForm.lessonsCompleted, label: 'Lessons' },
        { value: studentForm.streakDays, label: 'Streak' },
      ]}
      achievements={studentForm.achievements.map((achievement) => ({
        icon: achievementIcons[achievementMetaById[achievement.achievementId]?.icon ?? 'target'],
        label: achievementMetaById[achievement.achievementId]?.label ?? achievement.achievementId,
        description: achievementMetaById[achievement.achievementId]?.description ?? 'Achievement details are not specified yet.',
        unlocked: achievement.unlocked,
      }))}
      tab={tab}
      onTabChange={setTab}
      tabs={[
          {
            value: 'profile',
            label: 'Profile',
            panel: (
              <StudentProfileTab
                student={studentForm}
                onChange={setStudentForm}
                canEdit={canManage}
                viewerRole={activeMockUser.role}
                onSave={() => {}}
              />
            ),
          },
          {
            value: 'calendar',
            label: 'Calendar',
            panel: <StudentCalendarTab lessons={lessons} />,
          },
          {
            value: 'schedule',
            label: 'Schedule',
            panel: (
              <StudentScheduleTab
                canEdit={canManage}
                lessonType={lessonType}
                setLessonType={setLessonType}
                date={date}
                setDate={setDate}
                time={time}
                setTime={setTime}
                recurrence={recurrence}
                setRecurrence={setRecurrence}
                comment={comment}
                setComment={setComment}
                onPlan={() => {
                  const newLesson: ScheduledLessonDto = {
                    id: `lesson-local-${Date.now()}`,
                    title: `${lessonType.charAt(0).toUpperCase() + lessonType.slice(1)} Lesson`,
                    type: lessonType as 'grammar' | 'vocabulary' | 'speaking' | 'listening',
                    date,
                    startTime: time,
                    endTime: calculateEndTime(time, 55),
                    duration: 55,
                    teacherId: studentForm.teacherId,
                    teacherName: studentForm.teacherName,
                    studentId: studentForm.id,
                    studentName: studentForm.fullName,
                    status: 'planned',
                    credited: false,
                    notes: comment,
                    order: 1,
                    recurrence,
                  };
                  setLessons((prev) => [...prev, newLesson]);
                  setDate('');
                  setTime('');
                  setRecurrence('none');
                  setComment('');
                  setTab('calendar');
                }}
              />
            ),
          },
      ]}
    />
  );
}
